#!/usr/bin/env node
/**
 * Validates that no source file has a static import of @s3administrator/cloud
 * outside of generated stubs tracked in .s3admin-stubs.
 *
 * Allowed patterns:
 *   - Files listed in .s3admin-stubs (generated by s3admin-cloud-setup)
 *   - Dynamic imports: await import("@s3administrator/cloud/...") or
 *     import("@s3administrator/cloud/...") (used with next/dynamic, try/catch, etc.)
 *   - require.resolve("@s3administrator/cloud") (runtime probe in plugin-registry)
 *
 * Disallowed:
 *   - Static `import ... from "@s3administrator/cloud/..."` in non-stub files
 *   - Static `export ... from "@s3administrator/cloud/..."` in non-stub files
 */

import { readFileSync, existsSync } from "node:fs"
import { resolve, dirname, relative } from "node:path"
import { fileURLToPath } from "node:url"
import { execSync } from "node:child_process"

const __dirname = dirname(fileURLToPath(import.meta.url))
const PROJECT_ROOT = resolve(__dirname, "..")

// Load .s3admin-stubs if it exists
const stubsPath = resolve(PROJECT_ROOT, ".s3admin-stubs")
const stubPaths = new Set()
if (existsSync(stubsPath)) {
  const content = readFileSync(stubsPath, "utf-8")
  for (const line of content.split("\n")) {
    const trimmed = line.trim()
    if (trimmed) stubPaths.add(trimmed)
  }
}

// Find all .ts/.tsx files under src/
let files
try {
  const output = execSync('find src -type f \\( -name "*.ts" -o -name "*.tsx" \\)', {
    cwd: PROJECT_ROOT,
    encoding: "utf-8",
  })
  files = output.trim().split("\n").filter(Boolean)
} catch {
  console.error("  WARN  Could not scan src/ directory")
  process.exit(0)
}

// Static import/export pattern: import/export ... from "@s3administrator/cloud/..."
const STATIC_IMPORT_RE =
  /^(?:import|export)\s+.*\s+from\s+["']@s3administrator\/cloud\b/

const violations = []

for (const filePath of files) {
  // Skip files tracked as generated stubs
  if (stubPaths.has(filePath)) continue

  const fullPath = resolve(PROJECT_ROOT, filePath)
  if (!existsSync(fullPath)) continue

  const content = readFileSync(fullPath, "utf-8")
  const lines = content.split("\n")

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]
    if (!line.includes("@s3administrator/cloud")) continue

    // Allow dynamic imports and require.resolve
    if (
      line.includes("await import(") ||
      line.includes("import(") && !STATIC_IMPORT_RE.test(line.trim()) ||
      line.includes("require.resolve(")
    ) {
      continue
    }

    // Check for static import/export
    if (STATIC_IMPORT_RE.test(line.trim())) {
      violations.push({ file: filePath, line: i + 1, text: line.trim() })
    }
  }
}

if (violations.length > 0) {
  console.error(
    "\n  ERROR: Static @s3administrator/cloud imports found in non-stub files.\n"
  )
  console.error(
    "  Non-generated files must NOT use static imports from the cloud package.\n" +
      "  Use next/dynamic or await import() with a try/catch fallback instead.\n"
  )
  for (const v of violations) {
    console.error(`    ${v.file}:${v.line}`)
    console.error(`      ${v.text}\n`)
  }
  console.error(
    "  Fix: Replace static imports with dynamic imports (next/dynamic or await import()).\n" +
      "  If this is a generated stub, ensure it is tracked in .s3admin-stubs.\n"
  )
  process.exit(1)
}

console.log("  OK  No unguarded static @s3administrator/cloud imports")
